class Solution:
    def shortestPathAllKeys(self, grid):
        # Brute BFS, identical state model but recomputing the all-keys target
        # by scanning the grid and using a plain visited set.
        from collections import deque
        rows = len(grid)
        cols = len(grid[0])
        all_keys = 0
        start = None
        for r in range(rows):
            for c in range(cols):
                ch = grid[r][c]
                if ch == '@':
                    start = (r, c)
                elif ch.islower():
                    all_keys |= (1 << (ord(ch) - ord('a')))
        q = deque([(start[0], start[1], 0, 0)])
        visited = {(start[0], start[1], 0)}
        while q:
            r, c, keys, dist = q.popleft()
            if keys == all_keys:
                return dist
            for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                nr, nc = r + dr, c + dc
                if 0 <= nr < rows and 0 <= nc < cols:
                    ch = grid[nr][nc]
                    if ch == '#':
                        continue
                    nk = keys
                    if ch.islower():
                        nk |= (1 << (ord(ch) - ord('a')))
                    if ch.isupper() and not (keys & (1 << (ord(ch) - ord('A')))):
                        continue
                    if (nr, nc, nk) not in visited:
                        visited.add((nr, nc, nk))
                        q.append((nr, nc, nk, dist + 1))
        return -1

