class Solution:
    def shortestPathAllKeys(self, grid):
        from collections import deque
        rows, cols = len(grid), len(grid[0])
        target = 0
        sr = sc = 0
        for r in range(rows):
            for c in range(cols):
                ch = grid[r][c]
                if ch == '@':
                    sr, sc = r, c
                elif 'a' <= ch <= 'f':
                    target |= 1 << (ord(ch) - ord('a'))
        q = deque([(sr, sc, 0)])
        seen = {(sr, sc, 0)}
        steps = 0
        while q:
            for _ in range(len(q)):
                r, c, keys = q.popleft()
                if keys == target:
                    return steps
                for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    nr, nc = r + dr, c + dc
                    if not (0 <= nr < rows and 0 <= nc < cols):
                        continue
                    ch = grid[nr][nc]
                    if ch == '#':
                        continue
                    if 'A' <= ch <= 'F' and not (keys & (1 << (ord(ch) - ord('A')))):
                        continue
                    nk = keys
                    if 'a' <= ch <= 'f':
                        nk |= 1 << (ord(ch) - ord('a'))
                    if (nr, nc, nk) not in seen:
                        seen.add((nr, nc, nk))
                        q.append((nr, nc, nk))
            steps += 1
        return -1

