var shortestPathAllKeys = function(grid) {
    const rows = grid.length, cols = grid[0].length;
    let target = 0, sr = 0, sc = 0;
    for (let r = 0; r < rows; r++) {
        for (let c = 0; c < cols; c++) {
            const ch = grid[r][c];
            if (ch === '@') { sr = r; sc = c; }
            else if (ch >= 'a' && ch <= 'f') target |= 1 << (ch.charCodeAt(0) - 97);
        }
    }
    let queue = [[sr, sc, 0]];
    const seen = new Set([sr + ',' + sc + ',0']);
    let steps = 0;
    while (queue.length) {
        const next = [];
        for (const [r, c, keys] of queue) {
            if (keys === target) return steps;
            for (const [dr, dc] of [[1, 0], [-1, 0], [0, 1], [0, -1]]) {
                const nr = r + dr, nc = c + dc;
                if (nr < 0 || nr >= rows || nc < 0 || nc >= cols) continue;
                const ch = grid[nr][nc];
                if (ch === '#') continue;
                if (ch >= 'A' && ch <= 'F' && !(keys & (1 << (ch.charCodeAt(0) - 65)))) continue;
                let nk = keys;
                if (ch >= 'a' && ch <= 'f') nk |= 1 << (ch.charCodeAt(0) - 97);
                const key = nr + ',' + nc + ',' + nk;
                if (!seen.has(key)) {
                    seen.add(key);
                    next.push([nr, nc, nk]);
                }
            }
        }
        queue = next;
        steps += 1;
    }
    return -1;
};
